sys_script_include.script:
var SUMSApplicationUtils = Class.create();
SUMSApplicationUtils.prototype = {
    initialize: function() {},


    generateAppNumber: function(currentRecord) {
        var countGA = new GlideAggregate('x_1920019_smart_0_sums_application');
        countGA.addAggregate('COUNT');
        countGA.query();

        var count = 0;
        if (countGA.next()) {
            count = countGA.getAggregate('COUNT');
        }

        var nextNum = 1001 + parseInt(count, 10);
        currentRecord.u_application_number = 'ADM' + nextNum;
    },


    createStudentMaster: function(feeRecord) {
        var appGR = new GlideRecord('x_1920019_smart_0_sums_application');

        if (appGR.get(feeRecord.u_application)) {
            var studentGR = new GlideRecord('x_1920019_smart_0_student_master');
            studentGR.initialize();

            var randId = Math.floor(1000 + Math.random() * 9000);
            studentGR.u_student_id = 'STU' + randId;
            studentGR.u_roll_number = 'RL' + randId;

            studentGR.u_student_name = appGR.u_student_name;
            studentGR.u_email = appGR.u_email;
            studentGR.u_course = appGR.u_course; 

            var studentSysId = studentGR.insert();

            appGR.u_status = 'approved'; 
            appGR.update();

            return studentSysId;
        }
        return null;
    },

    type: 'SUMSApplicationUtils'
};
